# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from functools import wraps
import time
import hashlib
import json

app = Flask(__name__)

es = Elasticsearch([{
    'host': 'localhost',
    'port': 9200,
    'scheme': 'http'
}])

CACHE = {}
CACHE_TTL = 300

def cache_key(query):
    return hashlib.md5(query.encode()).hexdigest()

def cached(ttl=CACHE_TTL):
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            key = cache_key(request.args.get('q', ''))
            now = time.time()
            
            if key in CACHE:
                cached_time, cached_result = CACHE[key]
                if now - cached_time < ttl:
                    return cached_result
            
            result = f(*args, **kwargs)
            CACHE[key] = (now, result)
            return result
        return wrapper
    return decorator

@app.route('/api/search', methods=['GET'])
@cached(ttl=300)
def search_products():
    query = request.args.get('q', '').strip()
    page = request.args.get('page', 1, type=int)
    size = request.args.get('size', 20, type=int)
    
    if not query:
        return jsonify({
            'error': 'Query parameter "q" is required',
            'products': [],
            'total': 0
        }), 400
    
    if size > 100:
        size = 100
    
    from_offset = (page - 1) * size
    
    search_body = {
        'query': {
            'multi_match': {
                'query': query,
                'fields': ['name^3', 'description^2', 'category', 'brand', 'tags'],
                'type': 'best_fields',
                'fuzziness': 'AUTO'
            }
        },
        'highlight': {
            'fields': {
                'name': {},
                'description': {}
            }
        },
        'from': from_offset,
        'size': size
    }
    
    try:
        response = es.search(index='products', body=search_body)
        
        products = []
        for hit in response['hits']['hits']:
            product = {
                'id': hit['_id'],
                'score': hit['_score'],
                **hit['_source']
            }
            
            if 'highlight' in hit:
                product['highlight'] = hit['highlight']
            
            products.append(product)
        
        return jsonify({
            'query': query,
            'products': products,
            'total': response['hits']['total']['value'],
            'page': page,
            'size': size,
            'took': response['took']
        }), 200
        
    except Exception as e:
        return jsonify({
            'error': 'Search failed',
            'message': str(e),
            'products': [],
            'total': 0
        }), 500

@app.route('/api/search/suggest', methods=['GET'])
def search_suggest():
    query = request.args.get('q', '').strip()
    
    if not query or len(query) < 2:
        return jsonify({'suggestions': []}), 200
    
    search_body = {
        'suggest': {
            'product-suggest': {
                'prefix': query,
                'completion': {
                    'field': 'name_suggest',
                    'size': 10,
                    'skip_duplicates': True
                }
            }
        }
    }
    
    try:
        response = es.search(index='products', body=search_body)
        
        suggestions = []
        for option in response['suggest']['product-suggest'][0]['options']:
            suggestions.append({
                'text': option['text'],
                'score': option['_score']
            })
        
        return jsonify({'suggestions': suggestions}), 200
        
    except Exception as e:
        return jsonify({
            'error': 'Suggestion failed',
            'message': str(e),
            'suggestions': []
        }), 500

@app.route('/health', methods=['GET'])
def health_check():
    try:
        es.ping()
        return jsonify({'status': 'healthy', 'elasticsearch': 'connected'}), 200
    except:
        return jsonify({'status': 'unhealthy', 'elasticsearch': 'disconnected'}), 503

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)